 1→<!--
 2→  @component User settings wrapper
 3→
 4→  Properties:
 5→  - `username String!`: Empty string if auth. is disabled, otherwise the username as string
 6→  - `isApi Bool!`: Is currently logged in user api authority
 7→-->
 8→
 9→<script>
10→  import { getContext } from "svelte";
11→  import UserOptions from "./user/UserOptions.svelte";
12→  import PlotRenderOptions from "./user/PlotRenderOptions.svelte";
13→  import PlotColorScheme from "./user/PlotColorScheme.svelte";
14→
15→  /* Svelte 5 Props */
16→  let {
17→    username,
18→    isApi
19→  } = $props();
20→
21→  /* Const Init */
22→  const ccconfig = getContext("cc-config");
23→  
24→  /* State Init */
25→  let message = $state({ msg: "", target: "", color: "#d63384" });
26→  let displayMessage = $state(false);
27→  let cbmode = $state(ccconfig?.plotConfiguration_colorblindMode || false);
28→
29→  /* Functions */
30→  async function handleSettingSubmit(event, setting) {
31→    event.preventDefault();
32→
33→    const selector = setting.selector
34→    const target = setting.target
35→    let form = document.querySelector(selector);
36→    let formData = new FormData(form);
37→    try {
38→      const res = await fetch(form.action, { method: "POST", body: formData });
39→      if (res.ok) {
40→        let text = await res.text();
41→        if (formData.get("key") === "plotConfiguration_colorblindMode") {
42→          cbmode = JSON.parse(formData.get("value"));
43→        }
44→        popMessage(text, target, "#048109");
45→      } else {
46→        let text = await res.text();
47→        throw new Error("Response Code " + res.status + "-> " + text);
48→      }
49→    } catch (err) {
50→      popMessage(err, target, "#d63384");
51→    }
52→
53→    return false;
54→  }
55→
56→  function popMessage(response, restarget, rescolor) {
57→    message = { msg: response, target: restarget, color: rescolor };
58→    displayMessage = true;
59→    setTimeout(function () {
60→      displayMessage = false;
61→    }, 3500);
62→  }
63→</script>
64→
65→<UserOptions config={ccconfig} {username} {isApi} bind:message bind:displayMessage updateSetting={(e, newSetting) => handleSettingSubmit(e, newSetting)}/>
66→<PlotRenderOptions config={ccconfig} bind:message bind:displayMessage updateSetting={(e, newSetting) => handleSettingSubmit(e, newSetting)}/>
67→<PlotColorScheme config={ccconfig} bind:cbmode bind:message bind:displayMessage updateSetting={(e, newSetting) => handleSettingSubmit(e, newSetting)}/>
68→

