 17→// resolveResolutionFromPolicy reads the user's resample policy preference and
 18→// computes a resolution based on job duration and metric frequency. Returns nil
 19→// if the user has no policy set.
 20→func resolveResolutionFromPolicy(ctx context.Context, duration int64, cluster string, metrics []string) *int {
 21→	user := repository.GetUserFromContext(ctx)
 22→	if user == nil {
 23→		return nil
 24→	}
 25→
 26→	conf, err := repository.GetUserCfgRepo().GetUIConfig(user)
 27→	if err != nil {
 28→		return nil
 29→	}
 30→
 31→	policyVal, ok := conf["plotConfiguration_resamplePolicy"]
 32→	if !ok {
 33→		return nil
 34→	}
 35→	policyStr, ok := policyVal.(string)
 36→	if !ok || policyStr == "" {
 37→		return nil
 38→	}
 39→
 40→	policy := metricdispatch.ResamplePolicy(policyStr)
 41→	targetPoints := metricdispatch.TargetPointsForPolicy(policy)
 42→	if targetPoints == 0 {
 43→		return nil
 44→	}
 45→
 46→	// Find the smallest metric frequency across the requested metrics
 47→	frequency := smallestFrequency(cluster, metrics)
 48→	if frequency <= 0 {
 49→		return nil
 50→	}
 51→
 52→	res := metricdispatch.ComputeResolution(duration, int64(frequency), targetPoints)
 53→	return &res
 54→}
