 56→// resolveResampleAlgo returns the resampling algorithm name to use, checking
 57→// the explicit GraphQL parameter first, then the user's preference.
 58→func resolveResampleAlgo(ctx context.Context, resampleAlgo *model.ResampleAlgo) string {
 59→	if resampleAlgo != nil {
 60→		return strings.ToLower(resampleAlgo.String())
 61→	}
 62→
 63→	user := repository.GetUserFromContext(ctx)
 64→	if user == nil {
 65→		return ""
 66→	}
 67→
 68→	conf, err := repository.GetUserCfgRepo().GetUIConfig(user)
 69→	if err != nil {
 70→		return ""
 71→	}
 72→
 73→	algoVal, ok := conf["plotConfiguration_resampleAlgo"]
 74→	if !ok {
 75→		return ""
 76→	}
 77→	algoStr, ok := algoVal.(string)
 78→	if !ok {
 79→		return ""
 80→	}
 81→
 82→	return algoStr
 83→}
