 85→// smallestFrequency returns the smallest metric timestep (in seconds) among the
 86→// requested metrics for the given cluster. Falls back to 0 if nothing is found.
 87→func smallestFrequency(cluster string, metrics []string) int {
 88→	cl := archive.GetCluster(cluster)
 89→	if cl == nil {
 90→		return 0
 91→	}
 92→
 93→	minFreq := 0
 94→	for _, mc := range cl.MetricConfig {
 95→		if len(metrics) > 0 {
 96→			found := false
 97→			for _, m := range metrics {
 98→				if mc.Name == m {
 99→					found = true
100→					break
101→				}
102→			}
103→			if !found {
104→				continue
105→			}
106→		}
107→		if minFreq == 0 || mc.Timestep < minFreq {
108→			minFreq = mc.Timestep
109→		}
110→	}
111→
112→	return minFreq
113→}
