194→func setupTaglistRoute(i InfoType, r *http.Request) InfoType {
195→	jobRepo := repository.GetJobRepository()
196→	tags, counts, err := jobRepo.CountTags(repository.GetUserFromContext(r.Context()))
197→	tagMap := make(map[string][]map[string]any)
198→	if err != nil {
199→		cclog.Warnf("GetTags failed: %s", err.Error())
200→		i["tagmap"] = tagMap
201→		return i
202→	}
203→	// Reduces displayed tags for unauth'd users
204→	userAuthlevel := repository.GetUserFromContext(r.Context()).GetAuthLevel()
205→	// Uses tag.ID as second Map-Key component to differentiate tags with identical names
206→	if userAuthlevel >= 4 { // Support+ : Show tags for all scopes, regardless of count
207→		for _, tag := range tags {
208→			tagItem := map[string]any{
209→				"id":    tag.ID,
210→				"name":  tag.Name,
211→				"scope": tag.Scope,
212→				"count": counts[fmt.Sprint(tag.Type, tag.Name, tag.ID)],
213→			}
214→			tagMap[tag.Type] = append(tagMap[tag.Type], tagItem)
215→		}
216→	} else if userAuthlevel < 4 && userAuthlevel >= 2 { // User+ : Show global and admin scope only if at least 1 tag used, private scope regardless of count
217→		for _, tag := range tags {
218→			tagCount := counts[fmt.Sprint(tag.Type, tag.Name, tag.ID)]
219→			if ((tag.Scope == "global" || tag.Scope == "admin") && tagCount >= 1) || (tag.Scope != "global" && tag.Scope != "admin") {
220→				tagItem := map[string]any{
221→					"id":    tag.ID,
222→					"name":  tag.Name,
223→					"scope": tag.Scope,
224→					"count": tagCount,
225→				}
226→				tagMap[tag.Type] = append(tagMap[tag.Type], tagItem)
227→			}
228→		}
229→	} // auth < 2 return nothing for this route
230→
231→	i["tagmap"] = tagMap
232→	return i
233→}
