236→func buildFilterPresets(query url.Values) map[string]any {
237→	filterPresets := map[string]any{}
238→
239→	if query.Get("cluster") != "" {
240→		filterPresets["cluster"] = query.Get("cluster")
241→	}
242→	if query.Get("partition") != "" {
243→		filterPresets["partition"] = query.Get("partition")
244→	}
245→	if query.Get("project") != "" {
246→		filterPresets["project"] = query.Get("project")
247→		filterPresets["projectMatch"] = "eq"
248→	}
249→	if query.Get("jobName") != "" {
250→		filterPresets["jobName"] = query.Get("jobName")
251→	}
252→	if len(query["user"]) != 0 {
253→		if len(query["user"]) == 1 {
254→			filterPresets["user"] = query.Get("user")
255→			filterPresets["userMatch"] = "contains"
256→		} else {
257→			filterPresets["user"] = query["user"]
258→			filterPresets["userMatch"] = "in"
259→		}
260→	}
261→	if len(query["state"]) != 0 {
262→		filterPresets["state"] = query["state"]
263→	}
264→	if query.Get("shared") != "" {
265→		filterPresets["shared"] = query.Get("shared")
266→	}
267→	if query.Get("schedule") != "" {
268→		filterPresets["schedule"] = query.Get("schedule")
269→	}
270→	if rawtags, ok := query["tag"]; ok {
271→		tags := make([]int, len(rawtags))
272→		for i, tid := range rawtags {
273→			var err error
274→			tags[i], err = strconv.Atoi(tid)
275→			if err != nil {
276→				tags[i] = -1
277→			}
278→		}
279→		filterPresets["tags"] = tags
280→	}
281→	if query.Get("duration") != "" {
282→		parts := strings.Split(query.Get("duration"), "-")
283→		if len(parts) == 2 {
284→			if parts[0] == "lessthan" {
285→				lt, lte := strconv.Atoi(parts[1])
286→				if lte == nil {
287→					filterPresets["duration"] = map[string]int{"lessThan": lt, "from": 0, "to": 0}
288→				}
289→			} else if parts[0] == "morethan" {
290→				mt, mte := strconv.Atoi(parts[1])
291→				if mte == nil {
292→					filterPresets["duration"] = map[string]int{"moreThan": mt, "from": 0, "to": 0}
293→				}
294→			} else {
295→				a, e1 := strconv.Atoi(parts[0])
296→				b, e2 := strconv.Atoi(parts[1])
297→				if e1 == nil && e2 == nil {
298→					filterPresets["duration"] = map[string]int{"from": a, "to": b}
299→				}
300→			}
301→		}
302→	}
303→	if query.Get("node") != "" {
304→		filterPresets["node"] = query.Get("node")
305→	}
306→	if query.Get("numNodes") != "" {
307→		parts := strings.Split(query.Get("numNodes"), "-")
308→		if len(parts) == 2 {
309→			if parts[0] == "lessthan" {
310→				lt, lte := strconv.Atoi(parts[1])
311→				if lte == nil {
312→					filterPresets["numNodes"] = map[string]int{"from": 1, "to": lt}
313→				}
314→			} else if parts[0] == "morethan" {
315→				mt, mte := strconv.Atoi(parts[1])
316→				if mte == nil {
317→					filterPresets["numNodes"] = map[string]int{"from": mt, "to": 0}
318→				}
319→			} else {
320→				a, e1 := strconv.Atoi(parts[0])
321→				b, e2 := strconv.Atoi(parts[1])
322→				if e1 == nil && e2 == nil {
323→					filterPresets["numNodes"] = map[string]int{"from": a, "to": b}
324→				}
325→			}
326→		}
327→	}
328→	if query.Get("numHWThreads") != "" {
329→		parts := strings.Split(query.Get("numHWThreads"), "-")
330→		if len(parts) == 2 {
331→			if parts[0] == "lessthan" {
332→				lt, lte := strconv.Atoi(parts[1])
333→				if lte == nil {
334→					filterPresets["numHWThreads"] = map[string]int{"from": 1, "to": lt}
335→				}
336→			} else if parts[0] == "morethan" {
337→				mt, mte := strconv.Atoi(parts[1])
338→				if mte == nil {
339→					filterPresets["numHWThreads"] = map[string]int{"from": mt, "to": 0}
340→				}
341→			} else {
342→				a, e1 := strconv.Atoi(parts[0])
343→				b, e2 := strconv.Atoi(parts[1])
344→				if e1 == nil && e2 == nil {
345→					filterPresets["numHWThreads"] = map[string]int{"from": a, "to": b}
346→				}
347→			}
348→		}
349→	}
350→	if query.Get("numAccelerators") != "" {
351→		parts := strings.Split(query.Get("numAccelerators"), "-")
352→		if len(parts) == 2 {
353→			if parts[0] == "lessthan" {
354→				lt, lte := strconv.Atoi(parts[1])
355→				if lte == nil {
356→					filterPresets["numAccelerators"] = map[string]int{"from": 1, "to": lt}
357→				}
358→			} else if parts[0] == "morethan" {
359→				mt, mte := strconv.Atoi(parts[1])
360→				if mte == nil {
361→					filterPresets["numAccelerators"] = map[string]int{"from": mt, "to": 0}
362→				}
363→			} else {
364→				a, e1 := strconv.Atoi(parts[0])
365→				b, e2 := strconv.Atoi(parts[1])
366→				if e1 == nil && e2 == nil {
367→					filterPresets["numAccelerators"] = map[string]int{"from": a, "to": b}
368→				}
369→			}
370→		}
371→	}
372→	if len(query["dbId"]) != 0 {
373→		filterPresets["dbId"] = query["dbId"]
374→	}
375→	if query.Get("jobId") != "" {
376→		if len(query["jobId"]) == 1 {
377→			filterPresets["jobId"] = query.Get("jobId")
378→			filterPresets["jobIdMatch"] = "eq"
379→		} else {
380→			filterPresets["jobId"] = query["jobId"]
381→			filterPresets["jobIdMatch"] = "in"
382→		}
383→	}
384→	if query.Get("arrayJobId") != "" {
385→		if num, err := strconv.Atoi(query.Get("arrayJobId")); err == nil {
386→			filterPresets["arrayJobId"] = num
387→		}
388→	}
389→	if query.Get("startTime") != "" {
390→		parts := strings.Split(query.Get("startTime"), "-")
391→		if len(parts) == 2 { // Time in seconds, from - to
392→			a, e1 := strconv.ParseInt(parts[0], 10, 64)
393→			b, e2 := strconv.ParseInt(parts[1], 10, 64)
394→			if e1 == nil && e2 == nil {
395→				filterPresets["startTime"] = map[string]string{
396→					"from": time.Unix(a, 0).Format(time.RFC3339),
397→					"to":   time.Unix(b, 0).Format(time.RFC3339),
398→				}
399→			}
400→		} else { // named range
401→			filterPresets["startTime"] = map[string]string{
402→				"range": query.Get("startTime"),
403→			}
404→		}
405→	}
406→	if query.Get("energy") != "" {
407→		parts := strings.Split(query.Get("energy"), "-")
408→		if len(parts) == 2 {
409→			if parts[0] == "lessthan" {
410→				lt, lte := strconv.Atoi(parts[1])
411→				if lte == nil {
412→					filterPresets["energy"] = map[string]int{"from": 1, "to": lt}
413→				}
414→			} else if parts[0] == "morethan" {
415→				mt, mte := strconv.Atoi(parts[1])
416→				if mte == nil {
417→					filterPresets["energy"] = map[string]int{"from": mt, "to": 0}
418→				}
419→			} else {
420→				a, e1 := strconv.Atoi(parts[0])
421→				b, e2 := strconv.Atoi(parts[1])
422→				if e1 == nil && e2 == nil {
423→					filterPresets["energy"] = map[string]int{"from": a, "to": b}
424→				}
425→			}
426→		}
427→	}
428→	if len(query["stat"]) != 0 {
429→		statList := make([]map[string]any, 0)
430→		for _, statEntry := range query["stat"] {
431→			parts := strings.Split(statEntry, "-")
432→			if len(parts) == 3 { // Metric Footprint Stat Field, from - to
433→				if parts[1] == "lessthan" {
434→					lt, lte := strconv.ParseInt(parts[2], 10, 64)
435→					if lte == nil {
436→						statEntry := map[string]any{
437→							"field": parts[0],
438→							"from":  1,
439→							"to":    lt,
440→						}
441→						statList = append(statList, statEntry)
442→					}
443→				} else if parts[1] == "morethan" {
444→					mt, mte := strconv.ParseInt(parts[2], 10, 64)
445→					if mte == nil {
446→						statEntry := map[string]any{
447→							"field": parts[0],
448→							"from":  mt,
449→							"to":    0,
450→						}
451→						statList = append(statList, statEntry)
452→					}
453→				} else {
454→					a, e1 := strconv.ParseInt(parts[1], 10, 64)
455→					b, e2 := strconv.ParseInt(parts[2], 10, 64)
456→					if e1 == nil && e2 == nil {
