593→// resamplingForUser returns a ResampleConfig that incorporates the user's
594→// resample policy preference. If the user has a policy set, it creates a
595→// policy-derived config with targetPoints and trigger. Otherwise falls back
596→// to the global config.
597→func resamplingForUser(conf map[string]any) *config.ResampleConfig {
598→	globalCfg := config.Keys.EnableResampling
599→
600→	policyVal, ok := conf["plotConfiguration_resamplePolicy"]
601→	if !ok {
602→		return globalCfg
603→	}
604→	policyStr, ok := policyVal.(string)
605→	if !ok || policyStr == "" {
606→		return globalCfg
607→	}
608→
609→	policy := metricdispatch.ResamplePolicy(policyStr)
610→	targetPoints := metricdispatch.TargetPointsForPolicy(policy)
611→	if targetPoints == 0 {
612→		return globalCfg
613→	}
614→
615→	// Build a policy-derived config: targetPoints + trigger, no resolutions array
616→	return &config.ResampleConfig{
617→		TargetPoints: targetPoints,
618→		Trigger:      targetPoints / 4,
619→	}
620→}
