528→                  const target = (numX * timestep) / resampleTrigger;
529→                  newRes = resampleResolutions.reduce(function(prev, curr) {
530→                    return (Math.abs(curr - target) < Math.abs(prev - target) ? curr : prev);
531→                  });
532→                }
533→                // Prevents non-required dispatches
534→                if (newRes && timestep !== newRes) {
535→                  onZoom({
536→                    newRes: newRes,
537→                    lastZoomState: u?.scales,
538→                    lastThreshold: thresholds?.normal
539→                  });
540→                }
541→              } else {
542→                onZoom({
543→                  lastZoomState: u?.scales,
544→                  lastThreshold: thresholds?.normal
545→                });
546→              };
547→            };
548→          },
549→        ]
550→      },
551→      scales: {
552→        x: { time: false },
553→        y: maxY ? { min: 0, max: (maxY * 1.1) } : {auto: true}, // Add some space to upper render limit
554→      },
