567→      opts.width = ren_width;
568→      opts.height = ren_height;
569→      
570→      if (plotSync) {
571→        opts.cursor.sync = { 
572→          key: plotSync.key,
573→          scales: ["x", null],
574→        }
575→      }
576→
577→      if (zoomState && metricConfig?.aggregation == "avg") {
578→        opts.scales = {...zoomState}
579→      } else if (zoomState && metricConfig?.aggregation == "sum") {
